#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

int numberOfArrays(string s, int k) {
    int n = s.length();
    vector<int> arr(n);
    int sum = 0;

    for (int i = 0; i < n; i++) {
        arr[i] = s[i] - '0';
        sum += arr[i];
    }

    int mod = 1000000007; // 10^9 + 7 (modulus)
    int result = sum % mod;

    for (int i = 0; i < n; i++) {
        result = (result * 10) % mod;
        result = (result * arr[i]) % mod;
    }

    return result;
}
```

